import collections

def sliding_window_maximum(nums: list[int], k: int) -> list[int]:
    if not nums or k == 0:
        return []

    result = []
    dq = collections.deque() # Stores indices

    for i in range(len(nums)):
        # Remove elements from the front of the deque that are outside the current window
        if dq and dq[0] < i - k + 1:
            dq.popleft()

        # Remove elements from the back of the deque that are smaller than the current element
        # This maintains the deque in decreasing order of values
        while dq and nums[dq[-1]] <= nums[i]:
            dq.pop()

        # Add current element's index to the back of the deque
        dq.append(i)

        # If the window has fully formed, the front of the deque is the maximum
        if i >= k - 1:
            result.append(nums[dq[0]])

    return result
